/**
 * Mejora 7 (Versículo del Día) — ADR-007.
 *
 * Array estático de versículos bíblicos bilingües (365, ~un año sin repetir).
 * La selección diaria es pura (sin API ni DB): `dayOfYear % verses.length`,
 * así todos los estudiantes ven el mismo versículo el mismo día.
 *
 * Criterio de selección: versículos conocidos, denominacionalmente neutros
 * (sin doctrinas específicas ni libros deuterocanónicos), con tono de sabiduría
 * y fe activa, relevantes para jóvenes de 13–17 años. Texto en español LATAM
 * neutro (es-419): sin "vosotros", sin arcaísmos.
 */

export interface Verse {
  textEs: string;
  textEn: string;
  referenceEs: string;
  referenceEn: string;
}

